const { execFileSync } = require('child_process');

const inputPath = $json.input_path;
const outputPath = $json.output_path;

const args = [
  '-y',
  '-i',
  inputPath,
  '-vf',
  'scale=1920:1080',
  '-c:v',
  'libx264',
  '-crf',
  '18',
  '-preset',
  'medium',
  '-c:a',
  'aac',
  '-b:a',
  '192k',
  '-af',
  'loudnorm=-16:I=-16:LRA=11:TP=-1.5',
  outputPath
];

try {
  const result = execFileSync('ffmpeg', args, { encoding: 'utf8' });
  return [{ json: { result: 'success', output: result } }];
} catch (error) {
  return [{ json: { result: 'error', error: error.message } }];
}
